class Shape {
public:
    virtual double area() = 0;
};

class Square : public Shape {
public:
    double side;
    Square(double s) : side(s) {}
    double area() override {
        return side * side;
    }
};

Shape *shapes[2] = { new Square(3), new Square(5) };
double total = 0;
for (int i = 0; i < 2; i++) {
    total += shapes[i]->area();
}
cout << total;
